Set.Bottom:
(function() {
    const ewa = EWA.F.FOS["@SYS_FRAME_UNID"];
    //提交后台数据时执行的检查或附加数据处理
    ewa.DoPostBefore = function() {
        //附加数据处理
        // ewa.PostAddData = {add1:'a',add2:2};
        return true;
    };

    function getObj(exp) {
        return exp ? $('#f_@sys_frame_unid').find(exp) : $('#f_@sys_frame_unid');
    }

    function loadActionJson_SAct0() {
        const serId = getObj('#PC_SER_ID').val();
        let u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "SAct0");
        u1.AddParameter("ewa_ajax", "json");
        u1.AddParameter("PC_SER_ID", serId);

        let u = u1.GetUrl();
        $J(u, getObj('#PC_SER_TAG_ID')[0], 'SER_TAG_NAME', 'SER_TAG_ID', true, '@PC_SER_TAG_ID', function(s) {
            if ("@PC_SER_TAG_ID1") {
                getObj('#PC_SER_TAG_ID').trigger('change');
            }
        });
    }

    function loadActionJson_SAct1() {
        const serId = getObj('#PC_SER_ID').val();
        const serTagId = getObj('#PC_SER_TAG_ID').val();
        let u1 = new EWA_UrlClass(EWA.F.FOS["@SYS_FRAME_UNID"].Url);
        u1.AddParameter("ewa_action", "SAct1");
        u1.AddParameter("ewa_ajax", "json");
        u1.AddParameter("PC_SER_ID", serId);
        u1.AddParameter("PC_SER_TAG_ID", serTagId);

        let u = u1.GetUrl();
        $J(u, getObj('#PC_SER_TAG_ID1')[0], 'SER_TAG_NAME', 'SER_TAG_ID', true, '@PC_SER_TAG_ID1', function(s) {
            console.log(s)
        });
    }

    function init() {
        getObj('#PC_SER_ID').on('change', loadActionJson_SAct0)
        getObj('#PC_SER_TAG_ID').on('change', loadActionJson_SAct1)
        if ("@PC_SER_ID") {
            getObj('#PC_SER_ID').trigger('change');
        }
    }
    init();
})();

