INSERT INTO
    product_CAT (
        PC_NAME,
        PC_NAME_EN,
        PC_MEMO,
        PC_MEMO_EN,
        PC_PID,
        PC_LVL,
        PC_ORD,
        PC_CDATE,
        PC_MDATE,
        PC_SER_ID,
        PC_SER_TAG_ID,
        PC_STATUS
    )
VALUES
    (
        @PC_NAME,
        @PC_NAME_EN,
        @PC_MEMO,
        @PC_MEMO_EN,
        @PC_PID,
        @PC_LVL,
        @PC_ORD,
        @SYS_DATE,
        @SYS_DATE,
        @PC_SER_ID,
        @PC_SER_TAG_ID,
        'USED'
    )

